#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=1e5+10;int sm[N<<2];
vector<int> C[N<<2];int num[N],Ans=0,m;
int n;inline void build(int l=1,int r=n,int cur=1)
{
	if(l==r){sm[cur]=read();return;}int mid=(l+r)>>1;
	build(l,mid,cur<<1);build(mid+1,r,cur<<1|1);sm[cur]=sm[cur<<1]+sm[cur<<1|1];return;
}
inline void update(int k){if(!(sm[k]=sm[k<<1]+sm[k<<1|1]))for(int v:C[k])if(!(--num[v]))++Ans;}
inline void add(int ql,int qr,int pos,int l=1,int r=n,int cur=1)
{
	if(ql<=l&&r<=qr){C[cur].push_back(pos);++num[pos];return;}int mid=(l+r)>>1;
	if(ql<=mid)add(ql,qr,pos,l,mid,cur<<1);if(qr>mid)add(ql,qr,pos,mid+1,r,cur<<1|1);
}
inline void del(int pos,int l=1,int r=n,int cur=1)
{
	if(l==r){if(!(--sm[cur]))for(int v:C[cur])if(!(--num[v]))++Ans;return;}
	int mid=(l+r)>>1;pos<=mid?del(pos,l,mid,cur<<1):del(pos,mid+1,r,cur<<1|1);update(cur);
}
int main()
{
	n=read();m=read();build();rep(1,m,i){int l=read(),r=read();add(l,r,i);}
//	for(int v:C[9])printf("%d ",v);printf("qwq %d\n",num[2]);
	int T=read(),lst=0;while(T--){del((read()+lst-1)%n+1);printf("%d\n",lst=Ans);}
}
